void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    // Detect the first point where the ascending order is broken
    // This serves as an O(N) check for already-sorted data
    auto drop = std::adjacent_find(arr.begin(), arr.end(), std::greater<int>());
    if (drop == arr.end()) return;

    // Detect if the array is reverse-sorted
    // Using rbegin/rend allows the compiler to potentially use SIMD optimizations for is_sorted
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
        return;
    }

    // Adaptive Check: If there is only one "drop" and the rest of the array is sorted,
    // we have two sorted runs. This is common in rotated arrays or single-element shifts.
    auto split = drop + 1;
    if (std::is_sorted(split, arr.end())) {
        // If the array is a pure rotation (e.g., [4, 5, 1, 2, 3]), std::rotate is O(N) and in-place.
        if (arr.back() <= arr.front()) {
